import React from 'react';
import Trade from './Trade';

function TradeList(props) {
    const goodTrades = props.tradeList.filter(item => {
        return item.profitLoss>0
    })
    const badTrades = props.tradeList.filter(item => {
        return item.profitLoss<0
    })
    const amounts = props.tradeList.map(trade => trade.profitLoss)
    const totalProfitLoss =  amounts.reduce((acc, item) => (acc +=item),0)
    const successRate = (goodTrades.length/(goodTrades.length + badTrades.length))*100
    
    return(
        <div>
            <p>Success Rate  {successRate.toFixed(2)}%</p>
            <span>Total Profit {totalProfitLoss} P</span>
            <table>
                <tbody>
                    <tr>
                        <td>ID</td>
                        <td>Stock</td>
                        <td>Method</td>
                        <td>Quantity</td>
                        <td>P/L</td>
                        <td className='td-blank'></td>
                    </tr>
                </tbody>
                
            </table>
            { props.tradeList.map(trade => {
                return <Trade key={trade.id} trade={trade} deleteHandler={props.deleteHandler} />
            }) }       
        </div>
    )
}

export default TradeList;
